import{_ as a,c as t,a1 as o,o as i}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"DDoS attack using HOIC","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/9-denial-of-service/2-DDoS-using-HOIC.md","filePath":"categories/ethical-hacking-labs/9-denial-of-service/2-DDoS-using-HOIC.md"}'),r={name:"categories/ethical-hacking-labs/9-denial-of-service/2-DDoS-using-HOIC.md"};function n(s,e,c,h,l,d){return i(),t("div",null,e[0]||(e[0]=[o('<h1 id="ddos-attack-using-hoic" tabindex="-1">DDoS attack using HOIC <a class="header-anchor" href="#ddos-attack-using-hoic" aria-label="Permalink to &quot;DDoS attack using HOIC&quot;">​</a></h1><p>A distribute denial of services (DDoS) attack involves a group of compromised systems usually infected with Trojans used to perform a DoS attack on a target system or network.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Perform DDoS attack - HTTP flooding</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Kali Linux virtual machine (Target)</li><li>Windows Server, Windows 10 and Windows 7 virtual machine (Attackers)</li></ul><h3 id="overview-of-hoic" tabindex="-1">Overview of HOIC <a class="header-anchor" href="#overview-of-hoic" aria-label="Permalink to &quot;Overview of HOIC&quot;">​</a></h3><p>High Orbit Ion Cannon (HOIC) is a free, open-source network stress application developed by Anonymous, a hacktivist collective, to replace the Low Orbit Ion Cannon (LOIC). Used for denial of service (DoS) and distributed denial of service (DDoS) attacks, it functions by flooding target systems with junk HTTP GET and POST requests.</p><h2 id="log-in-to-virtual-machines" tabindex="-1">Log in to Virtual Machines <a class="header-anchor" href="#log-in-to-virtual-machines" aria-label="Permalink to &quot;Log in to Virtual Machines&quot;">​</a></h2><p>Before beginning this lab, turn on and log in to all virtual machines on this lab (Windows 7, 10, Server and Kali Linux).</p><p>Copy the <strong>High Orbit Ion Cannon (HOIC)</strong> folder onto all the Windows virtual machines(3).</p><h2 id="configure-hoic" tabindex="-1">Configure HOIC <a class="header-anchor" href="#configure-hoic" aria-label="Permalink to &quot;Configure HOIC&quot;">​</a></h2><p>Switch to the Windows 10 and open the HOIC (hoic2.1.exe)</p><p>On the HOIC GUI, click &#39;<strong>+</strong>&#39; to add the target.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ae12d7b7073ba34fd105724b932664d42326214a/hoic-1.png" alt="hoic-1"></p><p>On the HOIC - [Target] pop-up:</p><ol><li>Type the target URL (IP address of your Kali)</li><li>Slide the power bar to <strong>High</strong></li><li>Select <strong>GenericBoost.hoic</strong> booster from the drop-down list</li><li>Click <strong>add</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4d7add45a1ce5bb52c475b1419b2747fca8ce61d/hoic-4.png" alt="hoic-2"></li></ol><p>Set the <strong>THREADS</strong> value to <strong>20</strong> as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ae12d7b7073ba34fd105724b932664d42326214a/hoic-3.png" alt="hoic-3"></p><p><strong>Now repeat this process on every Windows virtual machine on your lab</strong>.</p><h2 id="perform-ddos-attack" tabindex="-1">Perform DDoS Attack <a class="header-anchor" href="#perform-ddos-attack" aria-label="Permalink to &quot;Perform DDoS Attack&quot;">​</a></h2><p>Once HOIC is configured on all machines, switch to each machine and click <strong>FIRE TEH LAZER!</strong>.</p><p align="center"><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4a96be03755e00ce6123ea2f6b022b77488744ec/hoic-5.png"></p> This initiates the DDoS attack on the target (Kali Linux). <p>Switch to the <strong>Kali Linux</strong> and launch the <strong>Wireshark</strong>.</p><p>Observe that Wireshark starts capturing a very large volume of packets, which means the machine is experiencing a huge number of incoming packets. These packets are coming from the <strong>Windows 7, Windows Server and Windows 10</strong> virtual machines.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4a96be03755e00ce6123ea2f6b022b77488744ec/hoic-6.png" alt="hoic-6"></p><p>In this lab, only three machines are demonstrated flooding a single machine. If there are a large number of machines performing flooding, then the target Kali Linux resources are completely consumed and the machine is overwhelmed.</p><p>In real time, a group of hackers operating hundreds or thousands of machines configure this tool on their machines, and simulate the DDoS attack by flooding a target machine/website at the same time. The target is overwhelmed and stops responding to user requests or starts dropping packets coming from legitimate users. The larger number of attacker machines, the higher the impact of the attack on the target machine/webste.</p><p>To stop the DDoS, click <strong>FIRE TEH LAZER!</strong> again, and then close the HOIC window in all the attacker virtual machines.</p>',30)]))}const p=a(r,[["render",n]]);export{u as __pageData,p as default};
